"use client"

import { LoaderCircleIcon, SendIcon, SquareIcon } from "lucide-react"

import { Button } from "@/components/ui/button"
import { Spinner } from "@/components/ui/spinner"
import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"

type ChatComposerStatus = "ready" | "submitted" | "streaming" | "error"

function ChatComposer({ className, ...props }: React.ComponentProps<"form">) {
  return (
    <form
      data-slot="chat-composer"
      className={cn(
        "flex min-w-0 flex-col gap-2 rounded-xl border bg-background p-2 shadow-sm focus-within:border-ring focus-within:ring-3 focus-within:ring-ring/50",
        className
      )}
      {...props}
    />
  )
}

function ChatComposerTextarea({
  className,
  ...props
}: React.ComponentProps<typeof Textarea>) {
  return (
    <Textarea
      data-slot="chat-composer-textarea"
      className={cn(
        "max-h-48 min-h-20 resize-none border-0 bg-transparent p-2 shadow-none focus-visible:ring-0",
        className
      )}
      {...props}
    />
  )
}

function ChatComposerToolbar({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-composer-toolbar"
      className={cn("flex items-center justify-between gap-2", className)}
      {...props}
    />
  )
}

function ChatComposerTools({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-composer-tools"
      className={cn("flex min-w-0 items-center gap-1", className)}
      {...props}
    />
  )
}

function ChatComposerSubmit({
  status = "ready",
  disabled,
  children,
  ...props
}: React.ComponentProps<typeof Button> & {
  status?: ChatComposerStatus
}) {
  const isBusy = status === "submitted" || status === "streaming"

  return (
    <Button
      data-slot="chat-composer-submit"
      type="submit"
      size="icon"
      disabled={disabled || status === "submitted"}
      aria-label={isBusy ? "Stop generation" : "Send message"}
      {...props}
    >
      {children ??
        (status === "streaming" ? (
          <SquareIcon aria-hidden="true" />
        ) : status === "submitted" ? (
          <Spinner aria-hidden="true" />
        ) : status === "error" ? (
          <LoaderCircleIcon aria-hidden="true" />
        ) : (
          <SendIcon aria-hidden="true" />
        ))}
    </Button>
  )
}

export {
  ChatComposer,
  ChatComposerSubmit,
  ChatComposerTextarea,
  ChatComposerToolbar,
  ChatComposerTools,
  type ChatComposerStatus,
}

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

type ChatMessageRole = "user" | "assistant" | "system" | "tool"

function ChatMessage({
  from = "assistant",
  className,
  ...props
}: React.ComponentProps<"article"> & {
  from?: ChatMessageRole
}) {
  return (
    <article
      data-slot="chat-message"
      data-role={from}
      className={cn(
        "group/chat-message flex w-full min-w-0 items-start gap-3 data-[role=user]:flex-row-reverse",
        className
      )}
      {...props}
    />
  )
}

function ChatMessageAvatar({
  src,
  fallback,
  className,
  ...props
}: React.ComponentProps<typeof Avatar> & {
  src?: string
  fallback?: React.ReactNode
}) {
  return (
    <Avatar
      data-slot="chat-message-avatar"
      size="sm"
      className={cn("mt-1", className)}
      {...props}
    >
      {src ? <AvatarImage src={src} alt="" /> : null}
      <AvatarFallback>{fallback ?? "AI"}</AvatarFallback>
    </Avatar>
  )
}

function ChatMessageBody({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-message-body"
      className={cn(
        "flex max-w-[min(42rem,85%)] min-w-0 flex-col gap-2 group-data-[role=user]/chat-message:items-end",
        className
      )}
      {...props}
    />
  )
}

function ChatMessageContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-message-content"
      className={cn(
        "rounded-xl bg-muted px-3 py-2 text-sm leading-6 text-foreground group-data-[role=assistant]/chat-message:bg-transparent group-data-[role=assistant]/chat-message:px-0 group-data-[role=assistant]/chat-message:py-0 group-data-[role=user]/chat-message:bg-primary group-data-[role=user]/chat-message:text-primary-foreground",
        className
      )}
      {...props}
    />
  )
}

function ChatMessageMeta({
  className,
  ...props
}: React.ComponentProps<typeof Badge>) {
  return (
    <Badge
      data-slot="chat-message-meta"
      variant="outline"
      className={cn("font-normal", className)}
      {...props}
    />
  )
}

function ChatMessageActions({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-message-actions"
      className={cn("flex items-center gap-1", className)}
      {...props}
    />
  )
}

export {
  ChatMessage,
  ChatMessageActions,
  ChatMessageAvatar,
  ChatMessageBody,
  ChatMessageContent,
  ChatMessageMeta,
  type ChatMessageRole,
}

import { MessageSquareIcon } from "lucide-react"

import {
  Empty,
  EmptyDescription,
  EmptyHeader,
  EmptyMedia,
  EmptyTitle,
} from "@/components/ui/empty"
import { cn } from "@/lib/utils"

function ChatThread({ className, ...props }: React.ComponentProps<"section">) {
  return (
    <section
      data-slot="chat-thread"
      className={cn("flex min-h-0 flex-1 flex-col bg-background", className)}
      {...props}
    />
  )
}

function ChatThreadContent({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-thread-content"
      role="log"
      aria-live="polite"
      aria-relevant="additions text"
      className={cn(
        "flex min-h-0 flex-1 flex-col gap-4 overflow-y-auto px-4 py-6",
        className
      )}
      {...props}
    />
  )
}

function ChatThreadFooter({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="chat-thread-footer"
      className={cn("shrink-0 border-t bg-background p-4", className)}
      {...props}
    />
  )
}

function ChatThreadEmpty({
  title = "Start a conversation",
  description = "Send a message to begin chatting with the assistant.",
  icon,
  className,
  children,
  ...props
}: React.ComponentProps<typeof Empty> & {
  title?: React.ReactNode
  description?: React.ReactNode
  icon?: React.ReactNode
}) {
  return (
    <Empty
      data-slot="chat-thread-empty"
      className={cn("border-0", className)}
      {...props}
    >
      <EmptyHeader>
        <EmptyMedia variant="icon">
          {icon ?? <MessageSquareIcon aria-hidden="true" />}
        </EmptyMedia>
        <EmptyTitle>{title}</EmptyTitle>
        <EmptyDescription>{description}</EmptyDescription>
      </EmptyHeader>
      {children}
    </Empty>
  )
}

export { ChatThread, ChatThreadContent, ChatThreadEmpty, ChatThreadFooter }

"use client"

import { ChevronDownIcon } from "lucide-react"

import { Badge } from "@/components/ui/badge"
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible"
import { cn } from "@/lib/utils"

type ChatToolCallState = "pending" | "running" | "completed" | "error"

function formatValue(value: unknown) {
  if (typeof value === "string") {
    return value
  }

  return JSON.stringify(value, null, 2)
}

function ChatToolCall({
  className,
  ...props
}: React.ComponentProps<typeof Collapsible>) {
  return (
    <Collapsible
      data-slot="chat-tool-call"
      className={cn("rounded-xl border bg-muted/40", className)}
      {...props}
    />
  )
}

function ChatToolCallHeader({
  name,
  state = "pending",
  className,
  children,
  ...props
}: React.ComponentProps<typeof CollapsibleTrigger> & {
  name: string
  state?: ChatToolCallState
}) {
  return (
    <CollapsibleTrigger
      data-slot="chat-tool-call-header"
      className={cn(
        "group flex w-full items-center justify-between gap-3 px-3 py-2 text-left text-sm outline-none focus-visible:ring-3 focus-visible:ring-ring/50",
        className
      )}
      {...props}
    >
      <span className="flex min-w-0 items-center gap-2">
        <span className="truncate font-medium">{name}</span>
        <Badge
          variant={state === "error" ? "destructive" : "secondary"}
          className="capitalize"
        >
          {state}
        </Badge>
      </span>
      {children ?? (
        <ChevronDownIcon
          aria-hidden="true"
          className="shrink-0 transition-transform group-data-[panel-open]:rotate-180"
        />
      )}
    </CollapsibleTrigger>
  )
}

function ChatToolCallContent({
  className,
  ...props
}: React.ComponentProps<typeof CollapsibleContent>) {
  return (
    <CollapsibleContent
      data-slot="chat-tool-call-content"
      className={cn("border-t px-3 py-3", className)}
      {...props}
    />
  )
}

function ChatToolCallInput({
  input,
  className,
  ...props
}: React.ComponentProps<"pre"> & {
  input: unknown
}) {
  return (
    <pre
      data-slot="chat-tool-call-input"
      className={cn(
        "max-h-72 overflow-auto rounded-lg bg-background p-3 text-xs leading-5 text-muted-foreground",
        className
      )}
      {...props}
    >
      {formatValue(input)}
    </pre>
  )
}

function ChatToolCallOutput({
  output,
  error,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  output?: React.ReactNode
  error?: React.ReactNode
}) {
  return (
    <div
      data-slot="chat-tool-call-output"
      data-error={Boolean(error)}
      className={cn(
        "rounded-lg bg-background p-3 text-sm data-[error=true]:text-destructive",
        className
      )}
      {...props}
    >
      {error ?? output}
    </div>
  )
}

export {
  ChatToolCall,
  ChatToolCallContent,
  ChatToolCallHeader,
  ChatToolCallInput,
  ChatToolCallOutput,
  type ChatToolCallState,
}
